<script setup lang="ts">
const supabase=useSupabaseClient<any>(), state=ref<any>(null), busy=ref(''), message=ref('')
const scope=reactive({purpose:'Review organizational capability configuration',scopes:'read',minutes:30}), offer=reactive({kind:'workflow',title:'Governed connector onboarding',description:'Reusable least-privilege connector setup',capabilities:'connectors:admin'}), collective=reactive({objective:'Improve delivery speed without weakening governance',operator:'ship faster',reviewer:'preserve proof and approval boundaries'}), warranty=reactive({provider:'remote-mcp',reliability:.95,quality:.85,max_cost_usd:.05,max_latency_ms:30000})
async function authed<T>(url:string,options:any={}){const{data:{session}}=await supabase.auth.getSession();return $fetch<T>(url,{...options,headers:{...(options.headers||{}),...(session?.access_token?{authorization:`Bearer ${session.access_token}`}:{})}})}
async function load(){state.value=await authed('/api/constitution/context')}
async function act(action:string,values:any={}){busy.value=action;message.value='';try{const result:any=await authed('/api/constitution/action',{method:'POST',body:{action,values}}); message.value=action==='release_replay'?`Replay preview ready; rollback remains confirmation-gated.`:`${action.replaceAll('_',' ')} completed and recorded.`;await load();return result}catch(e:any){message.value=e?.data?.message||e?.message||'Constitution action failed.'}finally{busy.value=''}}
function grant(){return act('temporary_scopes',{...scope,scopes:scope.scopes.split(',').map(x=>x.trim()).filter(Boolean)})} function publish(){return act('publish_offer',{...offer,capabilities:offer.capabilities.split(',').map(x=>x.trim()).filter(Boolean),terms:{price_usd:0,warranty:'best_efforts'}})} function synthesize(){return act('collective_intent',{objective:collective.objective,positions:[{stakeholder:'operator',priorities:[collective.operator],constraints:[]},{stakeholder:'reviewer',priorities:[collective.reviewer],constraints:['no unproved irreversible execution']}]})} function replay(){const id=state.value?.releases?.[0]?.id;if(id)return act('release_replay',{snapshot_id:id})}
onMounted(load)
</script>
<template><section id="execution-constitution" class="mt-5 rounded-xl border bg-white p-4" aria-labelledby="constitution-heading"><div class="flex flex-wrap items-start justify-between gap-3"><div><div class="text-[10px] font-semibold uppercase tracking-[.14em] text-emerald-700">Execution constitution</div><h2 id="constitution-heading" class="mt-1 text-sm font-semibold">Proof-carrying organizational execution</h2><p class="mt-1 max-w-3xl text-xs text-gray-500">Every command, permission, market exchange, collective decision, warranty, certification, and replay is bounded and receipted.</p></div><span v-if="state" class="rounded-full bg-emerald-50 px-2 py-1 text-[10px] text-emerald-700">{{state.proofs.length}} proofs · {{state.worlds.length}} worlds · {{state.releases.length}} release snapshots</span></div><div v-if="!state" class="mt-4 text-xs text-gray-400">Loading execution constitution…</div><template v-else><div class="mt-4 grid gap-3 lg:grid-cols-2"><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Organizational world model</h3><p class="mt-1 text-[10px] text-gray-500">Snapshot members, connectors, work, approvals, routes, costs, proofs, and causal assumptions.</p><button class="mt-3 rounded-lg bg-emerald-700 px-3 py-2 text-xs text-white" @click="act('capture_world',{label:'Current organizational world'})">Capture current world</button><p v-if="state.worlds[0]" class="mt-2 text-[10px] text-gray-500">Latest: {{state.worlds[0].label}} · {{state.worlds[0].metrics.open_tasks}} open tasks · {{state.worlds[0].metrics.pending_approvals}} approvals</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Autonomous least privilege</h3><div class="mt-2 grid grid-cols-2 gap-2"><input v-model="scope.purpose" class="col-span-2 rounded border px-2 py-2 text-xs"><input v-model="scope.scopes" class="rounded border px-2 py-2 text-xs"><input v-model.number="scope.minutes" type="number" min="1" max="1440" class="rounded border px-2 py-2 text-xs"><button class="col-span-2 rounded-lg bg-gray-900 px-3 py-2 text-xs text-white" @click="grant">Issue temporary scoped grant</button></div><p class="mt-2 text-[10px] text-gray-500">{{state.grants.filter((x:any)=>x.status==='active').length}} active grants; every grant expires automatically.</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Federated capability economy</h3><div class="mt-2 grid gap-2"><select v-model="offer.kind" class="rounded border px-2 py-2 text-xs"><option>skill</option><option>workflow</option><option>capacity</option><option>policy</option><option>connector</option><option>precedent_pack</option></select><input v-model="offer.title" class="rounded border px-2 py-2 text-xs"><input v-model="offer.description" class="rounded border px-2 py-2 text-xs"><input v-model="offer.capabilities" class="rounded border px-2 py-2 text-xs"><button class="rounded-lg bg-gray-900 px-3 py-2 text-xs text-white" @click="publish">Sign and publish capability</button></div><div class="mt-2 space-y-1"><div v-for="item in state.offers.slice(0,3)" :key="item.id" class="flex items-center justify-between rounded bg-gray-50 p-2 text-[10px]"><span>{{item.title}} · {{item.kind}}</span><button class="text-blue-600" @click="act('install_offer',{offer_id:item.id})">Verify and install</button></div></div></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Collective-intent compiler</h3><textarea v-model="collective.objective" rows="2" class="mt-2 w-full rounded border p-2 text-xs"></textarea><div class="mt-2 grid grid-cols-2 gap-2"><input v-model="collective.operator" class="rounded border px-2 py-2 text-xs" aria-label="Operator priority"><input v-model="collective.reviewer" class="rounded border px-2 py-2 text-xs" aria-label="Reviewer priority"></div><button class="mt-2 rounded-lg bg-gray-900 px-3 py-2 text-xs text-white" @click="synthesize">Compile governed consensus</button><p v-if="state.intents[0]" class="mt-2 text-[10px] text-gray-500">Latest: {{state.intents[0].decision}} · {{state.intents[0].conflicts.length}} conflicts surfaced</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Outcome warranty</h3><div class="mt-2 grid grid-cols-2 gap-2"><input v-model="warranty.provider" class="col-span-2 rounded border px-2 py-2 text-xs"><label class="text-[10px]">Reliability<input v-model.number="warranty.reliability" type="number" min="0" max="1" step=".01" class="mt-1 w-full rounded border px-2 py-1"></label><label class="text-[10px]">Quality<input v-model.number="warranty.quality" type="number" min="0" max="1" step=".01" class="mt-1 w-full rounded border px-2 py-1"></label><button class="col-span-2 rounded-lg bg-gray-900 px-3 py-2 text-xs text-white" @click="act('warranty',warranty)">Create governed warranty</button></div><p class="mt-2 text-[10px] text-gray-500">{{state.warranties.length}} warranties tracked with retry, alternate-provider, refund, and incident remedies.</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Continuous accessibility certification</h3><p class="mt-1 text-[10px] text-gray-500">Certify keyboard, screen-reader, reduced-motion, high-contrast, large-text, and concise-cognition profiles.</p><button class="mt-3 rounded-lg bg-gray-900 px-3 py-2 text-xs text-white" @click="act('accessibility_certification',{deployment_url:'https://www.madeus.cc'})">Run certification</button><p v-if="state.certifications[0]" class="mt-2 text-[10px]" :class="state.certifications[0].status==='passed'?'text-emerald-600':'text-red-600'">Latest certification: {{state.certifications[0].status}} · contract v{{state.certifications[0].contract_version}}</p></article><article class="rounded-xl border p-4 lg:col-span-2"><h3 class="text-xs font-semibold">Time-travel release replay</h3><p class="mt-1 text-[10px] text-gray-500">Capture passport, providers, accessibility, world metrics, and navigation; compare historical state before any rollback.</p><div class="mt-3 flex flex-wrap gap-2"><button class="rounded-lg bg-gray-900 px-3 py-2 text-xs text-white" @click="act('release_snapshot',{label:'Verified release checkpoint'})">Capture release state</button><button :disabled="!state.releases.length" class="rounded-lg border px-3 py-2 text-xs disabled:opacity-40" @click="replay">Preview latest replay</button></div><div class="mt-3 grid gap-2 md:grid-cols-3"><div v-for="item in state.releases.slice(0,3)" :key="item.id" class="rounded-lg bg-gray-50 p-2 text-[10px]"><b>{{item.label}}</b><br>{{item.state_digest.slice(0,14)}}… · nav v{{item.navigation_contract_version}}</div></div></article></div><article class="mt-3 rounded-xl border p-4"><h3 class="text-xs font-semibold">Proof envelope ledger</h3><div class="mt-2 grid gap-2 md:grid-cols-2"><div v-for="proof in state.proofs.slice(0,6)" :key="proof.id" class="rounded-lg bg-gray-50 p-2 text-[10px]"><b>{{proof.action_type}}</b> · {{proof.status}}<br><span class="text-gray-500">{{proof.intent}} · {{proof.proof_digest.slice(0,14)}}…</span></div></div></article></template><p v-if="message" role="status" class="mt-3 rounded-lg bg-gray-50 p-2 text-xs text-gray-600">{{message}}</p></section></template>
